import {
  Container,
  Typography,
  Box,
  AppBar,
  Toolbar,
  Button,
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableRow,
  Paper,
} from "@mui/material";

import "./BoardPage.css";

function BoardPage() {
  const posts = [
    {
      id: 1,
      title: "공지사항",
      author: "관리자",
      content: "게시판 테스트입니다.",
    },
    {
      id: 2,
      title: "React 공부",
      author: "홍길동",
      content: "Material UI 적용 중",
    },
    {
      id: 3,
      title: "Flask 연동 예정",
      author: "김철수",
      content: "백엔드 연결 예정",
    },
    {
      id: 4,
      title: "Flask 연동 예정",
      author: "김철수",
      content: "백엔드 연결 예정",
    },
    {
      id: 3,
      title: "Flask 연동 예정",
      author: "김철수",
      content: "백엔드 연결 예정",
    },
    {
      id: 3,
      title: "Flask 연동 예정",
      author: "김철수",
      content: "백엔드 연결 예정",
    },
    {
      id: 3,
      title: "Flask 연동 예정",
      author: "김철수",
      content: "백엔드 연결 예정",
    },
    {
      id: 3,
      title: "Flask 연동 예정",
      author: "김철수",
      content: "백엔드 연결 예정",
    },
    {
      id: 3,
      title: "Flask 연동 예정",
      author: "김철수",
      content: "백엔드 연결 예정",
    },
    {
      id: 3,
      title: "Flask 연동 예정",
      author: "김철수",
      content: "백엔드 연결 예정",
    },
    {
      id: 3,
      title: "Flask 연동 예정",
      author: "김철수",
      content: "백엔드 연결 예정",
    },
    {
      id: 3,
      title: "Flask 연동 예정",
      author: "김철수",
      content: "백엔드 연결 예정",
    },
    {
      id: 3,
      title: "Flask 연동 예정",
      author: "김철수",
      content: "백엔드 연결 예정",
    },
    {
      id: 3,
      title: "Flask 연동 예정",
      author: "김철수",
      content: "백엔드 연결 예정",
    },
    {
      id: 3,
      title: "Flask 연동 예정",
      author: "김철수",
      content: "백엔드 연결 예정",
    },
    {
      id: 3,
      title: "Flask 연동 예정",
      author: "김철수",
      content: "백엔드 연결 예정",
    },
  ];

  return (
    <>
      {/* Navbar */}
      <AppBar position="static" className="navbar" elevation={0}>
        <Toolbar className="navbar-toolbar">

          {/* 로고 영역 */}
          <Box sx={{ display: "flex", alignItems: "center" }}>
            <img src="/kw_logo.png" className="navbar-logo" />
          </Box>

          <Box sx={{ marginLeft: "auto" }}>
            <Button className="nav-button">게시물 등록</Button>
            <Button className="nav-button logout-btn">로그아웃</Button>
          </Box>
        </Toolbar>
      </AppBar>

      {/* 배너 (아래로 내림 + 여백) */}
      <Box className="board-header">
        <Typography variant="h4" className="board-title">
          게시판
        </Typography>
        <Typography className="board-subtitle">
          공지사항 및 게시글 목록
        </Typography>
      </Box>

      {/* 테이블 게시판 */}
      <Container className="board-container">

        <Paper className="board-table-wrapper">

          <Table>
            <TableHead>
              <TableRow className="table-head">
                <TableCell>ID</TableCell>
                <TableCell>제목</TableCell>
                <TableCell>작성자</TableCell>
              </TableRow>
            </TableHead>

            <TableBody>
              {posts.map((post) => (
                <TableRow key={post.id} className="table-row">
                  <TableCell>{post.id}</TableCell>
                  <TableCell>{post.title}</TableCell>
                  <TableCell>{post.author}</TableCell>
                </TableRow>
              ))}
            </TableBody>

          </Table>

        </Paper>
      </Container>
    </>
  );
}

export default BoardPage;
